// GALLERY V — The Electronic Brain (1945–1990)
window.ATLAS_EVENTS.push(
{ id:"eniac", year:1946, date:"1946", era:5, cat:"computing",
  title:"ENIAC",
  wiki:"ENIAC", gallery:["UNIVAC I","John Mauchly","Kathleen Antonelli"],
  summary:"The first general-purpose electronic computer is unveiled at Penn — 18,000 vacuum tubes, programmed by six women history nearly forgot.",
  importance:"Built for ballistics tables, ENIAC announced the electronic computing age (Colossus, earlier, stayed secret for decades). Its first programmers — six women, including Kathleen Antonelli and Jean Bartik — invented programming practice with no manuals and little credit. Its successor UNIVAC predicted Eisenhower's 1952 landslide on live television, fixing the 'electronic brain' in the public mind, and delivered the Census Bureau machine-computing's first civilian customer.",
  impact:{
    computing:"Electronic general-purpose computing leaves the lab; the commercial industry follows within five years.",
    labor:"'Computer' stops being a job title for human calculators — the first occupation fully absorbed by its machine namesake.",
    society:"The electronic brain enters popular culture, with prophecy and dread attached.",
    government:"State demand — ballistics, census, code-breaking — is computing's founding market." },
  causes:["turing1936","ww2","audion","hollerith"], effects:["transistor","dartmouth","attdecree1956"] },

{ id:"transistor", year:1947, date:"December 1947", era:5, cat:["computing","radio"],
  title:"The Transistor",
  wiki:"Transistor", gallery:["Bell Labs","John Bardeen","William Shockley"],
  summary:"Bell Labs demonstrates the device that will replace the vacuum tube — and, in time, become the most manufactured object in history.",
  importance:"Bardeen, Brattain, and Shockley's invention made electronics small, cool, cheap, and reliable. But its commercialization was shaped by antitrust: AT&T's regulated-monopoly status, formalized in the 1956 consent decree, kept the company out of computing and forced broad patent licensing — seeding an entire industry it could not own. Shockley's defection to Palo Alto, and the 'traitorous eight' who fled him to found Fairchild, planted Silicon Valley.",
  impact:{
    technology:"Solid-state electronics: the substrate of everything after 1950.",
    regulation:"The 1956 decree's licensing terms turn one company's invention into an industry's commons — antitrust as innovation policy.",
    labor:"Electronics manufacturing becomes a great global employer — and, offshored, a driver of globalized labor.",
    computing:"Makes the integrated circuit, and thus Moore's Law, physically possible." },
  causes:["audion"], effects:["ic1958","attdecree1956"] },

{ id:"coldwar", year:1947, date:"1947", era:5, cat:["general","law"],
  title:"The National Security Act: CIA & Five Eyes",
  wiki:"Central Intelligence Agency", gallery:["UKUSA Agreement","Cold War"],
  summary:"The U.S. builds a peacetime intelligence apparatus; the UKUSA agreement binds five anglophone powers into a signals-intelligence alliance.",
  importance:"Wartime intelligence did not demobilize: the National Security Act created the CIA, and the UKUSA Agreement formalized Five Eyes — the SIGINT-sharing alliance of the U.S., UK, Canada, Australia, and New Zealand that Snowden's documents would illuminate sixty-six years later. The surveillance practices of these agencies went essentially unregulated until FISA in 1978, a thirty-year statutory silence during which programs like SHAMROCK read international telegrams wholesale.",
  impact:{
    surveillance:"Peacetime mass interception becomes permanent institutional fact.",
    government:"The national-security state — classified budgets, covert action, secret law — is founded.",
    regulation:"Three decades pass before the first meaningful statutory oversight (FISA, 1978).",
    society:"The Cold War frame justifies, and conceals, domestic surveillance that the Church Committee will eventually expose." },
  causes:["ww2","wwi","russianrev","stalin"], effects:["nsa","churchcommittee","fisa"] },

{ id:"tafthartley", year:1947, date:"1947", era:5, cat:"law",
  title:"Taft-Hartley",
  wiki:"Taft–Hartley Act", gallery:["Labor unions in the United States","Harry S. Truman"],
  summary:"Congress, over Truman's veto, trims the Wagner Act: closed shops banned, 'right-to-work' authorized, union leaders made to swear anti-communist oaths.",
  importance:"The postwar strike wave of 1945–46 — the largest in American history — produced the counterstroke. Taft-Hartley outlawed secondary boycotts, authorized state right-to-work laws (which would hollow union density southward and westward for decades), and purged communists from union office. American labor law's high-water mark had lasted twelve years; the long ebb began here.",
  impact:{
    labor:"The legal terrain tilts back toward employers; the South is fortified against organizing.",
    regulation:"The Wagner framework survives but caged — the modern American labor-law stalemate is set.",
    government:"Anti-communism becomes an instrument of domestic labor discipline." },
  causes:["wagneract"], effects:["patco"] },

{ id:"indianindependence", year:1947, date:"1947", era:5, cat:"general",
  title:"Indian Independence & Partition",
  wiki:"Partition of India", gallery:["Mahatma Gandhi","Indian independence movement","Jawaharlal Nehru"],
  summary:"The Raj ends; partition displaces fourteen million and kills perhaps two million. Decolonization's largest single moment.",
  importance:"Gandhi's mass nonviolence — satyagraha, the salt march, the boycotts — had made empire ungovernable; postwar Britain conceded. India's Industrial Disputes Act (1947), built on the colonial Trade Unions Act (1926), founded the labor law of what becomes the world's most populous state. Ghana (1957) and the 'Year of Africa' (1960, seventeen independences) followed in the wave this opened: the dismantling of colonial labor-extraction systems worldwide.",
  impact:{
    government:"The decolonization era begins in earnest — empire's labor systems dismantled state by state.",
    labor:"New states inherit and rewrite colonial labor codes; development economics becomes a labor question.",
    society:"Nonviolent mass resistance is proven against the century's largest empire — King and others study it closely." },
  causes:["sepoymutiny"], effects:[] },

{ id:"shannon", year:1948, date:"1948", era:5, cat:["computing","encryption"],
  title:"Shannon's Information Theory",
  wiki:"A Mathematical Theory of Communication", gallery:["Claude Shannon","Information theory","Bit"],
  summary:"Claude Shannon defines information itself — the bit, channel capacity, redundancy — in one Bell Labs paper.",
  importance:"The founding document of the information age, and the foundation of information theory: Shannon showed that all communication — voice, text, image — reduces to one measurable currency, the bit, and that error-free transmission over noisy channels has exact mathematical limits. Every modem, compression format, and storage device is engineered against his theorems. Norbert Wiener's Cybernetics, published the same year, supplied the companion vision of feedback and control. No regulation ever touched the theory; it quietly underlies everything regulated since.",
  impact:{
    computing:"Information becomes a quantity — the conceptual foundation of the digital world.",
    technology:"Coding and compression theory enable telecommunications, storage, broadcasting, and the internet.",
    society:"'Information' becomes the name of the age — the lens through which biology, economics, and culture are rethought." },
  causes:["telegraph","turing1936"], effects:["arpanet"] },

{ id:"udhr", year:1948, date:"1948", era:5, cat:"law",
  title:"The Universal Declaration of Human Rights",
  wiki:"Universal Declaration of Human Rights", gallery:["Eleanor Roosevelt","United Nations"],
  summary:"Under Eleanor Roosevelt's chairmanship, the UN declares rights for all — including work, just pay, unions, rest, and privacy.",
  importance:"Drafted in the Holocaust's shadow, the Declaration wrote labor's demands into the human-rights canon: Article 23 (work, just remuneration, trade unions), Article 24 (rest and leisure, reasonable hours), and Article 12 (privacy — no arbitrary interference with correspondence). It became the basis of the European Convention (1950) and the treaty system through which, decades later, data protection would be argued as a fundamental right.",
  impact:{
    regulation:"The rights frame goes global; labor and privacy are written into it from the first draft.",
    labor:"Union rights and fair pay declared universal entitlements, not local bargains.",
    society:"A common moral vocabulary for claims against both states and corporations." },
  causes:["ww2","ilo","hitler"], effects:["gdpr"] },

{ id:"beveridge", year:1945, date:"1942–1948", era:5, cat:"law",
  title:"Beveridge & the Welfare State",
  wiki:"Beveridge Report", gallery:["National Health Service","Clement Attlee"],
  summary:"Britain's wartime blueprint against the 'five giants' — want, disease, ignorance, squalor, idleness — becomes the NHS and cradle-to-grave insurance.",
  importance:"The Beveridge Report (1942) sold out within hours; the Attlee government built it: comprehensive social insurance and the National Health Service (1948). The workhouse's negative template was finally inverted — security as right, not deterrent. Welfare-state expansion across postwar Europe, fueled partly by bloc competition with the Soviet model, defined three decades of social policy and the labor settlement underpinning them.",
  impact:{
    regulation:"The full welfare state arrives — Bismarck's invention completed in democratic form.",
    labor:"The postwar settlement: full employment as policy, security as citizenship.",
    society:"The 'cradle to grave' state reshapes life's risks — and its records: universal services mean universal registration.",
    surveillance:"Welfare administration extends the state's files to every citizen — benefit and dossier arrive together." },
  causes:["newpoorlaw","bismarck","ww2"], effects:[] },

{ id:"fairnessdoctrine", year:1949, date:"1949", era:5, cat:"law",
  title:"The Fairness Doctrine",
  wiki:"FCC fairness doctrine", gallery:["Federal Communications Commission","Talk radio"],
  summary:"The FCC requires broadcasters to cover controversy fairly — a rule whose 1987 repeal remakes American political media.",
  importance:"Built on the public-trustee framework of 1927, the doctrine governed broadcast political speech for thirty-eight years. Its Reagan-era repeal — justified by channel abundance and First Amendment arguments — released the talk-radio boom and presaged cable news: the partisan media environment of the present is, in part, the doctrine's absence. The episode is the atlas's cleanest demonstration that deregulation reshapes culture as surely as regulation does.",
  impact:{
    regulation:"Content obligations attach to spectrum licenses — then detach, with consequences.",
    society:"Repeal restructures American political discourse within a decade.",
    communications:"Defines the recurring question: do gatekeepers of mass attention owe the public balance?" },
  causes:["radioact1927","communicationsact"], effects:[] },

{ id:"orwell", year:1949, date:"1949", era:5, cat:"general",
  title:"Nineteen Eighty-Four",
  wiki:"Nineteen Eighty-Four", gallery:["George Orwell","Big Brother (Nineteen Eighty-Four)"],
  summary:"Orwell gives surveillance its permanent vocabulary: Big Brother, the telescreen, thoughtcrime, memory holes.",
  importance:"No statute followed the novel — but every surveillance debate since has been conducted partly in its language. Orwell distilled the totalitarian systems of his decade into an imaginative framework so durable that 'Orwellian' became the standing charge against every camera network, data program, and disinformation apparatus that followed. Sales spike with each scandal; the Snowden disclosures sent it back up the bestseller lists sixty-four years after publication.",
  impact:{
    society:"The cultural immune system against surveillance acquires its core metaphors.",
    surveillance:"Telescreen and Big Brother become the measuring rods of every real system built afterward.",
    communications:"Demonstrates fiction's regulatory power: shaping what publics will and won't accept." },
  causes:["stalin","hitler"], effects:["snowden"] },

{ id:"turingtest", year:1950, date:"1950", era:5, cat:"computing",
  title:"'Computing Machinery and Intelligence'",
  wiki:"Turing test", gallery:["Alan Turing","Computing Machinery and Intelligence"],
  summary:"Turing asks 'Can machines think?' — and proposes the imitation game to make the question answerable.",
  importance:"Turing's Mind paper anticipated and rebutted the objections — including Lady Lovelace's, that machines originate nothing — and predicted machines would one day converse indistinguishably from humans. The modern AI story unfolds in this paper's long shadow: the test it proposed became the field's popular benchmark, finally claimed in earnest by the conversational systems of the 2020s. Turing, prosecuted by the state he had helped save, did not live to see the field named.",
  impact:{
    computing:"AI acquires its founding question and its most famous benchmark.",
    society:"The thinking machine becomes a serious intellectual prospect rather than an automaton fantasy.",
    technology:"Frames machine intelligence as behavioral and testable — the engineering orientation the field keeps." },
  causes:["turing1936","lovelace"], effects:["dartmouth","chatgpt"] },

{ id:"treatyofdetroit", year:1950, date:"1950", era:5, cat:["general","law"],
  title:"The Treaty of Detroit",
  wiki:"Treaty of Detroit", gallery:["United Auto Workers","Walter Reuther"],
  summary:"GM and the UAW sign a five-year contract trading labor peace for pensions, health insurance, and cost-of-living wages.",
  importance:"Walter Reuther's UAW won what the state had not provided: private welfare — pensions, health coverage, automatic cost-of-living raises — in exchange for management's unchallenged control of production. The model spread across unionized industry and built the blue-collar middle class; it also tied American social insurance to employment, a fateful divergence from Beveridge's universalism whose consequences define U.S. policy fights to the present.",
  impact:{
    labor:"Collective bargaining delivers the American Dream — for the organized third of the workforce.",
    society:"Employer-based health care and pensions become the American norm by contract, not statute.",
    government:"The private welfare state substitutes for public provision — durable, and durably unequal." },
  causes:["wagneract","flint","ford"], effects:["patco"] },

{ id:"nsa", year:1952, date:"October 24, 1952", era:5, cat:"general",
  title:"The NSA Is Established",
  wiki:"National Security Agency", gallery:["Fort Meade, Maryland","Signals intelligence"],
  summary:"A presidential memorandum, itself classified, creates the signals-intelligence agency whose existence is denied for years — 'No Such Agency.'",
  importance:"Truman's secret directive centralized cryptologic work in an agency that became the largest intelligence employer on earth. Its programs — SHAMROCK's telegram trawling, decades of warrantless interception — operated without statutory framework until the Church Committee's exposures produced FISA (1978). Snowden's 2013 disclosures would reveal its digital-age successors: PRISM, XKeyscore, bulk metadata. The agency is the cabinet noir at planetary scale.",
  impact:{
    surveillance:"Industrial-scale interception becomes a permanent state function.",
    government:"Secret charter, secret budget, secret law — the deepest structure of the classified state.",
    regulation:"Its abuses summon the entire framework of intelligence oversight, from FISA to the USA FREEDOM Act.",
    technology:"Drives cryptography and computing research from behind the curtain — and battles their public spread in the crypto wars." },
  causes:["coldwar","ww2","cabinetnoir"], effects:["churchcommittee","fisa","prism","snowden"] },

{ id:"attdecree1956", year:1956, date:"1956", era:5, cat:"radio",
  title:"The 1956 Consent Decrees: AT&T and IBM",
  wiki:"Bell System", gallery:["Bell Labs","IBM","Western Electric"],
  summary:"AT&T is barred from computing and must license its patents; IBM must sell, not just lease, its machines. Two settlements quietly shape the industry for thirty years.",
  importance:"The AT&T decree settled the 1949 antitrust suit by confining the monopoly to telephony — meaning Bell Labs, the most inventive institution on earth, could not commercialize the transistor, Unix, or C, and instead licensed them broadly. The IBM decree broke machine leasing's lock-in and required patent licensing, opening room for independent hardware and software industries. Rarely has so much industrial structure been set by two settlements so few people read.",
  impact:{
    regulation:"Antitrust by consent decree proves able to redirect entire technological trajectories.",
    computing:"Transistor licensing and Unix's open spread are direct decree consequences — Silicon Valley grows in the opened space.",
    power:"Demonstrates the alternative to breakup: behavioral restraints that fence the monopolist out of the future.",
    technology:"The American computing industry's competitive structure is, in large part, a regulatory artifact." },
  causes:["kingsbury","transistor","hollerith","eniac"], effects:["carterfone","attbreakup","ibmpc"] },

{ id:"dartmouth", year:1956, date:"Summer 1956", era:5, cat:"computing",
  title:"Dartmouth: 'Artificial Intelligence' Is Named",
  wiki:"Dartmouth workshop", gallery:["John McCarthy (computer scientist)","Marvin Minsky","Claude Shannon"],
  summary:"McCarthy, Minsky, Shannon, and colleagues convene to study how 'every aspect of learning... can be so precisely described that a machine can be made to simulate it.'",
  importance:"The summer workshop's proposal coined the field's name and its founding wager. Both AI traditions trace to this generation: the symbolic school that dominated for decades, and the neural-network heresy — Rosenblatt's perceptron, two years later — that would lose the early battles and, half a century on, win the war. The cycle the workshop began — extravagant promise, partial delivery, winter, rebirth — is the field's recurring weather.",
  impact:{
    computing:"AI becomes a named research field with a program and patrons.",
    society:"The promise of machine intelligence enters public expectation, decades ahead of capability.",
    government:"Defense funding (ARPA after 1958) becomes AI's patron through every winter." },
  causes:["turingtest","eniac","lovelace"], effects:["perceptron","perceptronsbook","alexnet"] },

{ id:"ic1958", year:1958, date:"1958–1959", era:5, cat:"computing",
  title:"The Integrated Circuit",
  wiki:"Integrated circuit", gallery:["Jack Kilby","Robert Noyce","Fairchild Semiconductor"],
  summary:"Kilby at Texas Instruments and Noyce at Fairchild put whole circuits on single chips — the device Moore's Law will ride for sixty years.",
  importance:"The chip made computing's exponential miniaturization physically possible. It also exemplifies the source timeline's central observation about regulation's gaps: the integrated circuit, among the most consequential inventions in human history, never triggered specific regulation. It contributed to systems that did — every computer and phone in the later galleries — but the invention itself passed silently into the world's infrastructure.",
  impact:{
    technology:"Circuits become printable matter; electronics begins its exponential descent in cost.",
    computing:"The enabling substrate of the microprocessor, the PC, and the smartphone.",
    labor:"Chip fabrication founds new industrial regions — Silicon Valley first, then East Asia's manufacturing rise.",
    regulation:"A foundational technology with no regulatory pointer at all — the typical case, not the exception." },
  causes:["transistor"], effects:["mooreslaw","intel4004"] },

{ id:"perceptron", year:1958, date:"1958", era:5, cat:"computing",
  title:"Rosenblatt's Perceptron",
  wiki:"Perceptron", gallery:["Frank Rosenblatt","Artificial neural network"],
  summary:"A machine that learns from examples — the Navy demonstration promises computers that will 'walk, talk, see, write, reproduce itself and be conscious.'",
  importance:"Frank Rosenblatt's perceptron, simulated on an IBM 704 and built as the Mark I hardware, learned to classify images by adjusting connection weights — the founding artifact of the neural-network tradition. The New York Times relayed the Navy's extravagant claims, setting the field's pattern of promise and backlash: Minsky and Papert's 1969 critique would freeze the approach for a generation, until backpropagation and AlexNet vindicated Rosenblatt's instinct decades after his death.",
  impact:{
    computing:"Machine learning from data is born — the lineage running directly to deep learning.",
    society:"The first AI hype cycle inflates and detonates in public, a template repeated ever since.",
    technology:"Connectionism: intelligence as weighted networks rather than hand-written rules — the idea that eventually wins." },
  causes:["dartmouth"], effects:["perceptronsbook","backprop"] },

{ id:"bankamericard", year:1958, date:"1958", era:5, cat:"general",
  title:"The Credit Card",
  wiki:"BankAmericard", gallery:["Credit card","Visa Inc."],
  summary:"Bank of America drops 60,000 unsolicited cards on Fresno, California — mass consumer credit begins, and every purchase becomes a data point.",
  importance:"BankAmericard (later Visa) created mass-market revolving credit — and a transaction record of unprecedented granularity. Each swipe is a behavioral datum; the credit bureaus' files, growing since the 1860s, gained an exhaustive new feed. The ecosystem's abuses — secret files, no correction rights — produced the Fair Credit Reporting Act in 1970, the first major federal regulation of commercial data. The ATM (1967) and the barcode (1974) completed finance and retail's conversion into data-generating machinery.",
  impact:{
    surveillance:"Consumer life becomes continuously recorded as transaction streams.",
    society:"Credit access reshapes consumption, and credit scoring reshapes opportunity.",
    regulation:"Feeds directly into FCRA (1970) — and the Equal Credit Opportunity Act (1974), which finally let married women hold credit in their own names.",
    technology:"Payment networks become early planetary-scale real-time data systems." },
  causes:["creditreporting"], effects:["fcra"] },

{ id:"telstar", year:1962, date:"1962", era:5, cat:"radio",
  title:"Telstar & the Satellite Age",
  wiki:"Telstar", gallery:["Communications satellite","Sputnik 1"],
  summary:"The first active communications satellite relays live television across the Atlantic; Congress legislates within four months.",
  importance:"Sputnik (1957) had shocked America into founding NASA and ARPA — the agency that would build the internet's ancestor. Telstar made space commercial: live transatlantic TV, and the Communications Satellite Act passed the same year, creating Comsat. The four-month invention-to-statute interval echoes the Titanic chain: when a capability arrives visibly and at once, law can move fast. The satellite also gave surveillance its highest ground — reconnaissance from orbit, beyond any border.",
  impact:{
    communications:"The planet acquires real-time broadcast links; 'live via satellite' enters the language.",
    regulation:"One of the fastest technology-to-statute chains on record.",
    surveillance:"Orbital reconnaissance normalizes observation that no national airspace can refuse.",
    government:"Space becomes communications infrastructure and Cold War theater simultaneously." },
  causes:["coldwar"], effects:["arpanet"] },

{ id:"civilrightsact", year:1964, date:"1963–1965", era:5, cat:"law",
  title:"The Civil Rights Act & Voting Rights Act",
  wiki:"Civil Rights Act of 1964", gallery:["March on Washington for Jobs and Freedom","Martin Luther King Jr.","Voting Rights Act of 1965"],
  summary:"The March on Washington for Jobs and Freedom; then Title VII bans employment discrimination, and the franchise is federally protected.",
  importance:"The movement that overturned Plessy fused civil and labor demands — the 1963 march's full name claimed both, and King was assassinated in 1968 supporting Memphis's striking sanitation workers, whose signs read 'I AM A MAN.' Title VII created the EEOC and made discrimination in employment unlawful; the Voting Rights Act (1965) re-enfranchised the South. The FBI's surveillance and harassment of King — exposed by the Church Committee — runs through the same years: the atlas's starkest case of state surveillance aimed at a movement for rights.",
  impact:{
    labor:"Employment discrimination becomes federally actionable; Black workers begin entering occupations and unions long closed.",
    regulation:"The Reconstruction amendments are finally enforced by statute.",
    surveillance:"COINTELPRO against the movement shows the watchful state's political uses — fuel for the 1970s reckoning.",
    society:"The legal architecture of caste is dismantled; the social architecture proves harder." },
  causes:["emancipation","plessy"], effects:["churchcommittee"] },

{ id:"mooreslaw", year:1965, date:"1965", era:5, cat:"computing",
  title:"Moore's Law",
  wiki:"Moore's law", gallery:["Gordon Moore","Intel"],
  summary:"Gordon Moore observes that transistor density doubles roughly every year (later, two) — an observation that becomes the industry's self-fulfilling schedule.",
  importance:"Moore's 1965 article was extrapolation from four data points; it became a planning document the semiconductor industry conspired to keep true for six decades. Exponential cheapening of computation is the quiet engine of every later gallery: it is why the mainframe became the PC, the PC the phone, and the phone the neural network's host. No regulation ever addressed it; arguably more than any statute, it set the pace at which law fell behind.",
  impact:{
    technology:"Exponential improvement becomes the industry's coordinating expectation.",
    computing:"Computation's cost collapse enables each subsequent platform shift on schedule.",
    society:"Permanent technological acceleration becomes a background assumption of modern life — and of regulatory lag." },
  causes:["ic1958"], effects:["intel4004","alexnet"] },

{ id:"natdatacenter", year:1965, date:"1965", era:5, cat:"computing",
  title:"The National Data Center Is Rejected",
  wiki:"National Data Center", gallery:["United States Congress","Database"],
  summary:"A proposal to consolidate federal records into one databank dies under public and congressional fire — American privacy politics' founding victory.",
  importance:"The Johnson administration's plan to merge federal statistical records provoked hearings, headlines, and visions of dossier government; it was abandoned. The episode proved public resistance to centralized state data politically effective, and the anxieties it crystallized produced the HEW report (1973) and the Privacy Act (1974). It also set the enduring American pattern: the state's databank was blocked, while the private sector's — credit bureaus, then ad networks — grew without comparable challenge.",
  impact:{
    surveillance:"Centralized state data meets organized democratic refusal — once.",
    regulation:"Seeds the FIPPs and the Privacy Act within a decade.",
    society:"The 'databank' enters public fear; the computer becomes a civil-liberties issue.",
    government:"Drives data integration underground into agency-by-agency accretion rather than visible architecture." },
  causes:["hollerith","ssa1935"], effects:["fipps","privacyact"] },

{ id:"carterfone", year:1968, date:"1968", era:5, cat:"radio",
  title:"The Carterfone Decision",
  wiki:"Carterfone", gallery:["Federal Communications Commission","Modem"],
  summary:"The FCC rules that any lawful device that does no harm may connect to the phone network — AT&T's equipment monopoly falls.",
  importance:"Tom Carter's gadget acoustically coupled two-way radios to telephone lines; AT&T's tariffs forbade attaching anything to 'its' network. The FCC's 1968 ruling — invention to decision in three years, among the tightest chains in the source timeline — opened the network to modems, fax machines, and answering machines. As the timeline puts it flatly: without Carterfone, no consumer internet as we know it. The same year, MCI won authorization to compete in long distance, and the monopoly's long unraveling began.",
  impact:{
    regulation:"The open-network principle: connectivity as a right, not the carrier's gift.",
    communications:"The modem's legality is secured — the consumer internet's door unlocked twenty years early.",
    power:"First structural crack in the Bell monopoly; MCI's entry follows immediately.",
    technology:"Permissionless innovation at the network's edge becomes the rule that later defines the internet." },
  causes:["strowger","attdecree1956","bell"], effects:["attbreakup","arpanet"] },

{ id:"katz", year:1968, date:"1967–1968", era:5, cat:"law",
  title:"Katz v. United States",
  wiki:"Katz v. United States", gallery:["Telephone booth","Supreme Court of the United States"],
  summary:"The Fourth Amendment 'protects people, not places': a wiretap on a phone booth requires a warrant.",
  importance:"Olmstead (1928) had confined the Fourth Amendment to physical trespass — tapping wires outside the house was fair game. Katz overruled it: Charles Katz's calls from a glass booth carried a 'reasonable expectation of privacy.' The doctrine governs digital privacy to this day — narrowed by the third-party doctrine of Miller (1976), partially rescued in the cell-tower age by Carpenter (2018). Congress codified wiretap warrants the same year in the Wiretap Act.",
  impact:{
    regulation:"Constitutional privacy modernizes from property to expectation.",
    surveillance:"Warrants reach electronic eavesdropping — the wiretap meets the Fourth Amendment at last.",
    society:"The reasonable-expectation formula becomes the hinge on which every new technology's privacy turns." },
  causes:["usbillofrights","brandeis","bell"], effects:["miller","carpenter","ecpa"] },

{ id:"may68", year:1968, date:"1968", era:5, cat:"general",
  title:"1968: The Global Uprising",
  wiki:"May 68", gallery:["Prague Spring","Tlatelolco massacre","Protests of 1968"],
  summary:"Ten million French workers strike as students hold the Sorbonne; Prague's spring is crushed by tanks; Mexico City's students are massacred before the Olympics.",
  importance:"The largest general strike in French history nearly toppled de Gaulle; parallel risings swept Czechoslovakia (suppressed by Soviet invasion in August), Mexico (Tlatelolco, October), Germany, Italy, Japan, and the United States. 1968 fused labor, generational, and anti-war revolt into a single global moment — carried, for the first time, by television. The political and labor culture of the next half-century, from workplace democratization to the conservative counter-mobilization, descends from this year.",
  impact:{
    labor:"Labor militancy's postwar peak — and its collision with both capitalist and communist states.",
    society:"The first televised global protest wave; youth becomes a political category.",
    government:"States East and West answer with force, surveillance, and, eventually, accommodation." },
  causes:["pariscommune","treatyofdetroit"], effects:[] },

{ id:"arpanet", year:1969, date:"October 29, 1969", era:5, cat:"internet",
  title:"ARPANET Goes Live",
  wiki:"ARPANET", gallery:["Interface Message Processor","Leonard Kleinrock","J. C. R. Licklider"],
  summary:"UCLA sends 'LO' to Stanford before the system crashes — packet-switched networking's first two letters.",
  importance:"Sputnik begat ARPA; ARPA begat the network. Packet switching — data diced into routable packets — proved out across four nodes in 1969 and never stopped growing: email arrived in 1971 (and the first spam in 1978), TCP/IP in 1973–82, and the whole edifice passed into the commercial internet by 1990. The source timeline's verdict: this invention eventually produces the consumer internet, and through it the entire regulatory landscape from the 1996 Telecom Act to GDPR to the AI debates — every later gallery, downstream of two letters.",
  impact:{
    communications:"The internet's direct ancestor; networking becomes general-purpose infrastructure.",
    computing:"The network becomes part of the computer — distributed systems begin.",
    government:"Defense research funding builds the century's defining civilian infrastructure, unplanned.",
    society:"Email, newsgroups, and online community appear inside a decade — the social internet precedes the commercial one." },
  causes:["shannon","telstar","carterfone","cursus"], effects:["wwwproposal","ecpa"] },

{ id:"perceptronsbook", year:1969, date:"1969", era:5, cat:"computing",
  title:"Minsky, Papert & the First AI Winter",
  wiki:"Perceptrons (book)", gallery:["Marvin Minsky","Seymour Papert"],
  summary:"Perceptrons proves single-layer networks can't even compute XOR — and neural-network funding freezes for a generation.",
  importance:"Minsky and Papert's mathematical critique was correct about single layers and fatally discouraging about the field: agencies redirected money to symbolic AI, and connectionism entered exile. The sequel was a story of stubbornness — Hinton, LeCun, and Bengio carrying the approach through decades of disrepute until multi-layer networks trained by backpropagation did everything the critique's shadow said they couldn't. Science's gatekeeping, the episode shows, can delay a truth without killing it.",
  impact:{
    computing:"The first AI winter: a research lineage frozen by one authoritative book.",
    society:"Hype's collapse teaches AI's boom-bust rhythm — promise, disillusion, quiet persistence.",
    technology:"Symbolic AI's two-decade reign begins; the neural heresy waits for more data and faster chips." },
  causes:["perceptron","dartmouth"], effects:["backprop"] },

{ id:"fcra", year:1970, date:"1970", era:5, cat:"law",
  title:"The Fair Credit Reporting Act",
  wiki:"Fair Credit Reporting Act", gallery:["Credit score","Consumer protection"],
  summary:"After 110 years of unregulated dossiers, Americans gain the right to see, dispute, and correct their credit files.",
  importance:"The credit-reporting industry founded by R.G. Dun in the 1860s — and Equifax's predecessor in 1899 — had operated without regulation for over a century when congressional hearings documented its secret files and ruinous errors. FCRA was the first major federal regulation of consumer information industries: access, correction, and use limits. It remains the primary law of credit data — and the founding precedent for the rights-based approach (see your data, fix your data) that the FIPPs and GDPR would generalize.",
  impact:{
    regulation:"Commercial data meets federal law for the first time — a century after the industry's birth.",
    surveillance:"The dossier becomes partially visible to its subject.",
    society:"Credit reports and scores are domesticated into appealable bureaucracy rather than secret judgment.",
    technology:"Correction rights and permissible-purpose rules prefigure all later data-protection design." },
  causes:["creditreporting","bankamericard","ssa1935"], effects:["fipps","gdpr"] },

{ id:"oshact", year:1970, date:"1970", era:5, cat:"law",
  title:"OSHA",
  wiki:"Occupational Safety and Health Act (United States)", gallery:["Occupational Safety and Health Administration","Coal Mine Health and Safety Act"],
  summary:"Federal workplace-safety law arrives — the Factory Act's inspectors, 137 years on, in American form.",
  importance:"The Occupational Safety and Health Act created federal authority to set and inspect workplace standards, following the Coal Mine Health and Safety Act (1969) won after the Farmington disaster. The lineage runs straight from the 1833 Factory Act's inspectorate through Triangle's investigating commissions: documented death producing institutional eyes. OSHA's chronic underfunding — more workplaces than inspectors can visit in a century — keeps the old gap between law and enforcement alive.",
  impact:{
    labor:"A federal right to a safe workplace, enforceable in principle.",
    regulation:"The inspection state reaches its American maturity.",
    government:"Standard-setting agencies become the front line of labor protection as union density declines." },
  causes:["factoryact1833","triangle"], effects:[] },

{ id:"intel4004", year:1971, date:"1971", era:5, cat:"computing",
  title:"The Microprocessor",
  wiki:"Intel 4004", gallery:["Microprocessor","Federico Faggin"],
  summary:"Intel puts a computer's processor on one chip — built for a Japanese calculator, destined for everything.",
  importance:"The 4004 collapsed the computer's heart onto a fingernail of silicon. Within four years it begat the hobbyist machines (Altair, 1975) that begat Microsoft and Apple; within a decade, the IBM PC. The source timeline is blunt: without the microprocessor, no PC industry, no Microsoft antitrust case, no consumer internet. Moore's Law now had a vehicle that could carry computation into every object that uses electricity.",
  impact:{
    computing:"Computers become components — embeddable, personal, eventually ubiquitous.",
    technology:"General-purpose computation starts its migration into cars, tools, toys, and infrastructure.",
    labor:"Begins the automation of clerical and cognitive work that mainframes had only centralized." },
  causes:["ic1958","mooreslaw"], effects:["altair","ibmpc"] },

{ id:"fipps", year:1973, date:"1973", era:5, cat:"law",
  title:"The HEW Report: Fair Information Practices",
  wiki:"FTC fair information practice", gallery:["Privacy","Data Protection Directive"],
  summary:"'Records, Computers, and the Rights of Citizens' articulates the principles — notice, access, correction, purpose limits — that become the world's privacy grammar.",
  importance:"Responding to computerized records' spread and the National Data Center fight, the HEW advisory committee distilled the Fair Information Practice Principles: no secret systems; a person may see and correct their record; data gathered for one purpose shall not be used for another without consent. The FIPPs became the conceptual backbone of privacy law in most democracies — the Privacy Act (1974), the OECD guidelines (1980), the EU Directive (1995), and GDPR are all elaborations of this slim federal report.",
  impact:{
    regulation:"Privacy acquires its design principles — quoted, translated, and legislated worldwide for fifty years.",
    surveillance:"The subject's rights over the record become the organizing idea of data governance.",
    government:"A study commission's framework outlives and outgrows every statute it inspired." },
  causes:["natdatacenter","fcra","brandeis"], effects:["privacyact","gdpr"] },

{ id:"mobilephone", year:1973, date:"April 3, 1973", era:5, cat:"radio",
  title:"The First Cell Phone Call",
  wiki:"Martin Cooper (inventor)", gallery:["Motorola DynaTAC","Cellular network"],
  summary:"Motorola's Martin Cooper calls his Bell Labs rival from a Manhattan sidewalk on a two-pound prototype.",
  importance:"Commercial service took another decade (the DynaTAC 8000X, 1983), but the handheld call founded mobile telephony — the technology that would put a networked computer, and a location beacon, in most human pockets. The cellular architecture's defining by-product: to route calls, the network must always know roughly where you are. That fact, fifty years on, is what Carpenter v. United States is about.",
  impact:{
    communications:"Telephony detaches from place; the person, not the address, becomes the endpoint.",
    surveillance:"Cell-site location data is born with the network itself — tracking as an architectural side effect.",
    society:"Begins the road to the always-reachable, always-located human of the smartphone era." },
  causes:["bell","transistor"], effects:["iphone","carpenter"] },

{ id:"privacyact", year:1974, date:"1974", era:5, cat:"law",
  title:"The Privacy Act",
  wiki:"Privacy Act of 1974", gallery:["Watergate scandal","Federal Register"],
  summary:"Watergate-era America writes the FIPPs into federal law — for government records only.",
  importance:"Passed amid Watergate's revelations and the first Church-era disclosures, the Privacy Act applied fair-information principles to federal agency records: notice of systems, access, correction, use limits. Its boundary is its biography: it never touched the private sector, leaving credit bureaus, marketers, and eventually platforms to sectoral statutes and the FTC's general powers. The transatlantic fork dates from here — Europe generalized the principles to everyone; America confined them to the state.",
  impact:{
    regulation:"FIPPs become U.S. law — within the government's own filing cabinets.",
    surveillance:"Federal databanks acquire rules; private ones acquire customers.",
    government:"The U.S. sectoral approach to privacy is set, distinguishing it from Europe's omnibus path for the next half-century." },
  causes:["fipps","natdatacenter","ssa1935"], effects:["gdpr"] },

{ id:"churchcommittee", year:1975, date:"1975", era:5, cat:"law",
  title:"The Church Committee",
  wiki:"Church Committee", gallery:["Frank Church","COINTELPRO","Watergate scandal"],
  summary:"The Senate opens the intelligence agencies' files: COINTELPRO, SHAMROCK, mail-opening, and the campaign against Martin Luther King.",
  importance:"Post-Watergate, and following Seymour Hersh's reporting on CIA domestic spying, Frank Church's committee documented decades of abuse: FBI operations to disrupt civil rights and dissident groups, NSA programs reading Americans' telegrams, assassination plots abroad. 'The most important single committee investigation in Senate history' directly produced FISA (1978), the intelligence oversight committees, and the modern — if perennially strained — framework of surveillance accountability.",
  impact:{
    surveillance:"The secret state is publicly inventoried for the first time.",
    regulation:"FISA and standing congressional oversight are its direct offspring.",
    society:"Documented abuse converts surveillance from fringe fear to established fact — the deep context for receiving Snowden, four decades on.",
    government:"Establishes that intelligence agencies answer, at least episodically, to constitutional politics." },
  causes:["nsa","coldwar","frumentarii","civilrightsact"], effects:["fisa","snowden"] },

{ id:"miller", year:1976, date:"1976", era:5, cat:"law",
  title:"United States v. Miller: The Third-Party Doctrine",
  wiki:"United States v. Miller (1976)", gallery:["Bank secrecy","Fourth Amendment to the United States Constitution"],
  summary:"Records voluntarily shared with your bank lose Fourth Amendment protection — a doctrine that will swallow the digital age.",
  importance:"Miller held that information conveyed to a third party carries no reasonable expectation of privacy. In 1976 that meant bank records; in the networked era it meant nearly everything, since almost all digital life — email, location, browsing — passes through intermediaries. The doctrine became digital surveillance's broadest gateway until Carpenter (2018) declined to extend it to cell-site location history, the first major retreat in forty-two years.",
  impact:{
    surveillance:"The state's warrantless window onto records held by anyone but you.",
    regulation:"Forces privacy protection into statutes (ECPA) where the Constitution was read not to reach.",
    society:"To use the network is to shed protection — the doctrine's logic, finally challenged in the smartphone era." },
  causes:["katz"], effects:["carpenter"] },

{ id:"altair", year:1975, date:"1975–1977", era:5, cat:"computing",
  title:"The Personal Computer Arrives",
  wiki:"Altair 8800", gallery:["Apple II","Steve Wozniak","Bill Gates"],
  summary:"The Altair 8800 ships to hobbyists; Microsoft is founded to sell it BASIC; Apple's II (1977) takes the computer home.",
  importance:"The microprocessor met the hobbyist, and two companies that would each face the antitrust bar were born in the encounter: Gates and Allen writing Altair BASIC, Wozniak and Jobs hand-building the Apple I. VisiCalc (1979) gave the Apple II its business justification — the first killer app. Computing's center of gravity began shifting from institutions to individuals, with every consequence for power and privacy that the later galleries record.",
  impact:{
    computing:"Computing becomes personal property — the hacker garage replaces the machine room.",
    society:"The PC hobbyist culture seeds both Silicon Valley's mythology and its industries.",
    power:"Microsoft and Apple are founded — the platform gatekeepers of two later eras.",
    labor:"The spreadsheet begins white-collar work's quiet automation." },
  causes:["intel4004","attdecree1956"], effects:["ibmpc","appstore"] },

{ id:"fisa", year:1978, date:"1978", era:5, cat:"law",
  title:"FISA",
  wiki:"Foreign Intelligence Surveillance Act", gallery:["United States Foreign Intelligence Surveillance Court","National Security Agency"],
  summary:"Foreign-intelligence wiretaps get a statute, a secret court, and a warrant process — the Church Committee's legislative monument.",
  importance:"FISA ended the era of purely executive surveillance: foreign-intelligence interception inside the U.S. now required orders from the new FISA Court. The framework held for a generation, then was stretched by the PATRIOT Act (2001) and the FISA Amendments Act (2008) — whose Section 702 programs, revealed by Snowden, tested whether secret courts can meaningfully check secret agencies. The cabinet noir finally had a statute; the argument over its adequacy never closed.",
  impact:{
    regulation:"Intelligence surveillance is brought under law — secret law, but law.",
    surveillance:"The warrant principle reaches national-security interception, with carve-outs that grow under pressure.",
    government:"The FISA Court becomes the emblem of oversight's promise and its limits." },
  causes:["churchcommittee","nsa","cabinetnoir","coldwar"], effects:["patriotact","snowden"] },

{ id:"dengreform", year:1978, date:"1978", era:5, cat:"general",
  title:"China's Reform and Opening Up",
  wiki:"Chinese economic reform", gallery:["Deng Xiaoping","Special economic zones of China","Shenzhen"],
  summary:"Deng Xiaoping turns China toward the market — beginning the largest labor migration and industrial transformation in human history.",
  importance:"The most consequential economic policy shift of the late twentieth century: Special Economic Zones drew foreign capital, and over the following decades hundreds of millions moved from field to factory, making China the world's workshop. The source timeline calls it the most consequential single labor history of the past fifty years. China's WTO accession (2001) globalized the shock; its later fusion of market economy with the world's most comprehensive surveillance apparatus defines one of the three rival models — American platform, European regulation, Chinese state — contending in the present.",
  impact:{
    labor:"The greatest industrialization of labor ever — and, with it, the iron rice bowl's end and the world's factory's rise.",
    society:"Global manufacturing, trade, and consumption rewire around Chinese production.",
    government:"State-led capitalism joins the menu of modernities — with party control, not pluralism, as its constant.",
    surveillance:"Prosperity and monitoring grow together — the Great Firewall and social-credit experiments are reform's shadow." },
  causes:["meiji","stalin"], effects:["chinawto","greatfirewall"] },

{ id:"solidarity", year:1980, date:"1980", era:5, cat:"general",
  title:"Solidarity",
  wiki:"Solidarity (Polish trade union)", gallery:["Lech Wałęsa","Gdańsk Shipyard","Round Table Agreement"],
  summary:"Gdańsk's shipyard strike births the Soviet bloc's first independent union — ten million members within a year, and the lever that cracks communism.",
  importance:"Lech Wałęsa's electricians and shipwrights forced the Gdańsk Agreement: an independent, self-governing trade union inside a communist state. Martial law (1981) drove Solidarity underground but could not dissolve it; by 1989 the regime negotiated with the union it had banned, and Poland's semi-free elections began the bloc's collapse. The supreme irony of the atlas's labor wing: the workers' state, brought down by a workers' movement.",
  impact:{
    labor:"Demonstrates labor organization's power against the regime claiming to embody it.",
    government:"Begins the negotiated end of Eastern European communism.",
    society:"The strike rejoins the church, the shipyard, and the nation — civil society reborn through a union.",
    surveillance:"Survives one of history's densest informer states — organization as counter-surveillance." },
  causes:["russianrev","may68"], effects:["berlinwall"] },

{ id:"patco", year:1981, date:"1979–1981", era:5, cat:"general",
  title:"PATCO & the Neoliberal Turn",
  wiki:"Professional Air Traffic Controllers Organization (1968)", gallery:["Ronald Reagan","Margaret Thatcher"],
  summary:"Reagan fires 11,345 striking air-traffic controllers; with Thatcher's Britain, the Anglo-American assault on union power defines an era.",
  importance:"Thatcher's election (1979) and Reagan's mass dismissal of PATCO's strikers (1981) announced the neoliberal turn: deregulation, privatization, and the open use of state power against organized labor. Private-sector employers read the signal — permanent replacement of strikers normalized — and strike activity collapsed. The source timeline marks 1979–81 as a defining global inflection: four decades of declining labor power and rising inequality across the English-speaking world begin here.",
  impact:{
    labor:"The strike weapon is broken in America for a generation; union density enters long decline.",
    government:"The state's ancient employer-side reflex returns in modern dress — by executive order rather than statute.",
    society:"Inequality's forty-year climb begins; 'flexibility' becomes the labor market's official virtue.",
    regulation:"Deregulation becomes governing philosophy across telecom, finance, and transport — reshaping every network industry in this atlas." },
  causes:["tafthartley","treatyofdetroit","wright"], effects:["minersstrike"] },

{ id:"ibmpc", year:1981, date:"1981", era:5, cat:"computing",
  title:"The IBM PC & MS-DOS",
  wiki:"IBM Personal Computer", gallery:["MS-DOS","PC clone"],
  summary:"IBM ships a personal computer built from open parts — and licenses its operating system from a tiny company called Microsoft.",
  importance:"IBM's openness let 'clones' replicate the architecture; Microsoft's license let DOS — and later Windows — run on all of them. The hardware commoditized; the operating system became the choke point. Microsoft's resulting dominance is the direct subject of the 1998 antitrust case, and the episode is a standing lesson in platform economics: the layer everyone must license is the layer that rules. The IBM antitrust case, thirteen years old, was dismissed in 1982 — overtaken, prosecutors said, by exactly this market shift.",
  impact:{
    computing:"The PC standard: open hardware, proprietary platform software.",
    power:"Microsoft inherits the gatekeeper position IBM is simultaneously deemed to have lost.",
    labor:"The desktop computer begins restructuring office work universally.",
    regulation:"Sets the stage for the defining tech antitrust case of the century's end." },
  causes:["intel4004","altair","attdecree1956"], effects:["microsoftcase"] },

{ id:"attbreakup", year:1984, date:"1974–1984", era:5, cat:"radio",
  title:"The AT&T Breakup",
  wiki:"Breakup of the Bell System", gallery:["Regional Bell Operating Company","AT&T Corporation"],
  summary:"The 1974 antitrust suit ends in divestiture: on January 1, 1984, the Bell System becomes seven regional companies plus a competitive long-distance market.",
  importance:"Seventy years of regulated monopoly, eroded by Carterfone, MCI, and microwave and fiber economics, ended in the Modification of Final Judgment (1982) and the largest corporate dissolution ever executed. The breakup created the competitive environment the consumer internet grew up inside — the Baby Bells became the broadband providers of the 1990s, and long-distance competition collapsed prices. Standard Oil's precedent, finally applied to communications; the atlas's biggest demonstration that structural antitrust can still happen.",
  impact:{
    regulation:"Divestiture's second masterpiece — the regulated-monopoly century formally closes.",
    communications:"Competition and falling prices remake American telephony; the internet inherits the opened field.",
    power:"Proves even the best-lawyered monopoly in history can be dismantled — a precedent invoked in every platform case since.",
    technology:"Bell Labs' fragments seed the industry; the decree-bound giant's inventions finally commercialize freely." },
  causes:["kingsbury","carterfone","attdecree1956","standardoil","shermanact","bell"], effects:["telecomact","microsoftcase"] },

{ id:"volkszahlung", year:1983, date:"1983", era:5, cat:"law",
  title:"Germany's Census Verdict",
  wiki:"Volkszählungsurteil", gallery:["Federal Constitutional Court","Census in Germany"],
  summary:"The Federal Constitutional Court halts the census and declares a constitutional right to 'informational self-determination.'",
  importance:"Mass protests against a comprehensive census — in a country whose registries had served the Nazi machine, a memory the judgment's context made explicit — produced the foundational ruling of European data protection: individuals determine the disclosure and use of their own data, because people who cannot know who knows what about them will trim their freedom to fit. The doctrine flows directly into the EU Data Protection Directive (1995) and GDPR (2018). Domesday's logic, nine centuries on, finally meets a constitutional answer.",
  impact:{
    regulation:"Data protection becomes a fundamental right with a theory of democratic harm.",
    surveillance:"The census — the state's oldest instrument — is constitutionally tamed in the country that knew its worst use.",
    society:"Popular protest against data collection succeeds at constitutional scale.",
    government:"European and American privacy law's divergence becomes doctrine: dignity and self-determination versus sectoral patchwork." },
  causes:["ibmnazi","hitler","domesday","fipps"], effects:["dpd1995","gdpr"] },

{ id:"minersstrike", year:1984, date:"1984–1985", era:5, cat:"general",
  title:"The UK Miners' Strike",
  wiki:"1984–85 United Kingdom miners' strike", gallery:["National Union of Mineworkers","Battle of Orgreave"],
  summary:"A year-long strike against pit closures is defeated by stockpiled coal, militarized policing, and surveillance — British labor's Waterloo.",
  importance:"The Thatcher government had prepared for years: coal reserves built up, police coordinated nationally, the NUM's communications monitored by the security services. Orgreave's mounted charges televised the confrontation; the defeat broke Britain's most powerful union and reshaped industrial relations for decades. With PATCO, it bookends the Anglo-American neoliberal offensive — the state's ancient pattern, executed with modern logistics and modern eavesdropping.",
  impact:{
    labor:"British union power is broken at its strongest point; deindustrialization proceeds unresisted.",
    surveillance:"State surveillance of a domestic union becomes documented fact — MI5's role later acknowledged.",
    society:"Mining communities' destruction becomes the era's emblem of deindustrial abandonment.",
    government:"Demonstrates strike-breaking as planned state strategy, not improvisation." },
  causes:["patco"], effects:[] },

{ id:"sonybetamax", year:1984, date:"1984", era:5, cat:["law","tv"],
  title:"The Betamax Case",
  wiki:"Sony Corp. of America v. Universal City Studios, Inc.", gallery:["Betamax","Videocassette recorder"],
  summary:"Hollywood sues to ban the VCR; the Supreme Court holds that technology with substantial non-infringing uses cannot be outlawed.",
  importance:"Sony's Betamax (1975) threatened the studios, whose president told Congress the VCR was 'to the American film producer... as the Boston Strangler is to the woman home alone.' The Court's 5–4 Sony doctrine — home time-shifting is fair use; dual-use technology survives its abusers — became the charter of permissionless media innovation, invoked through Napster, BitTorrent, YouTube, and now the disputes over AI training. The VCR, far from strangling Hollywood, built its most profitable market.",
  impact:{
    regulation:"The Sony doctrine: copyright cannot veto a technology for its lawful uses.",
    technology:"Legal shelter for every later copying, hosting, and generating tool.",
    society:"Home recording normalizes personal control over media — the audience becomes the archivist.",
    power:"Incumbent industries' instinct to ban the new is judicially checked — narrowly, once." },
  causes:["statuteofanne"], effects:["napster","aitraining"] },

{ id:"bhopal", year:1984, date:"December 1984", era:5, cat:"general",
  title:"Bhopal",
  wiki:"Bhopal disaster", gallery:["Union Carbide","Bhopal"],
  summary:"A Union Carbide pesticide plant releases methyl isocyanate over a sleeping Indian city — thousands dead at once, tens of thousands eventually. The worst industrial disaster in history.",
  importance:"Cost-cutting at a U.S. corporation's Indian subsidiary — disabled safety systems, skeleton staffing — killed at least 3,800 people immediately and an estimated 16,000–30,000 in time, with compensation and accountability still contested decades later. Bhopal became the founding case of global supply-chain accountability: the question of what a corporation owes the workers and neighbors of its most distant operations, asked again at Rana Plaza (2013) and in every supplier-audit regime since.",
  impact:{
    labor:"Industrial risk's globalization exposed — hazards exported to where protections are weakest.",
    regulation:"Spurs right-to-know laws (including the U.S. EPCRA, 1986) and global industrial-safety frameworks.",
    society:"Corporate accountability across borders becomes a permanent, unresolved demand.",
    power:"The liability architecture of multinationals — subsidiaries as shields — enters public view." },
  causes:["factoryact1833"], effects:["ranaplaza"] },

{ id:"ecpa", year:1986, date:"1986", era:5, cat:"law",
  title:"ECPA & CFAA",
  wiki:"Electronic Communications Privacy Act", gallery:["Computer Fraud and Abuse Act","WarGames"],
  summary:"Congress extends wiretap law to electronic communications and criminalizes computer intrusion — statutes frozen in 1986's assumptions ever since.",
  importance:"ECPA stretched the 1968 Wiretap Act to email and data, with distinctions (180-day-old mail, 'remote computing services') that made sense on that year's modems and never again; it has not been fundamentally updated through four decades of total digital transformation. The CFAA — passed after WarGames alarmed Congress — became the federal hacking statute, first deployed against the Morris Worm (1988) and criticized ever since for elastic breadth. Law's snapshot problem, preserved in amber.",
  impact:{
    regulation:"Digital communications get statutory privacy — calibrated to 1986 and left there.",
    surveillance:"Stored-communications rules become the gateway for law-enforcement access to email and cloud data.",
    technology:"CFAA's 'unauthorized access' shapes — and chills — security research for decades.",
    society:"Demonstrates statutory obsolescence: technology's decades outrun the statute book's." },
  causes:["katz","arpanet"], effects:["morrisworm"] },

{ id:"backprop", year:1986, date:"1986", era:5, cat:"computing",
  title:"Backpropagation",
  wiki:"Backpropagation", gallery:["Geoffrey Hinton","Artificial neural network","David Rumelhart"],
  summary:"Rumelhart, Hinton, and Williams show how multi-layer neural networks can learn — the algorithm that ends the first AI winter's verdict.",
  importance:"The Nature paper popularized training deep networks by propagating error backward through layers — answering, in practice, the limitation Minsky and Papert had made canonical. Hinton's decades of persistence center here: connectionism worked, but needed data and compute that wouldn't exist for twenty-five more years. Backprop is the algorithm beneath AlexNet, the Transformer, and ChatGPT — the atlas's longest fuse between method and detonation.",
  impact:{
    computing:"Deep learning's core algorithm arrives — and waits a quarter-century for its hardware.",
    technology:"Learning from data re-established as AI's viable path.",
    society:"The patient heretics' vindication becomes one of science's great persistence stories." },
  causes:["perceptron","perceptronsbook"], effects:["alexnet"] },

{ id:"morrisworm", year:1988, date:"November 2, 1988", era:5, cat:["internet","computing"],
  title:"The Morris Worm",
  wiki:"Morris worm", gallery:["Computer worm","Robert Tappan Morris"],
  summary:"A graduate student's experiment cripples a tenth of the internet overnight — and produces the first CFAA conviction.",
  importance:"Robert Morris's self-replicating program, released from MIT to measure the network, replicated too well: thousands of machines down, the young internet's fragility exposed. His conviction was the CFAA's first major test — invention to prosecution in two years, one of the source timeline's tightest chains — and the incident created CERT and the security industry's institutional beginnings. The network's openness and its vulnerability were revealed as the same property.",
  impact:{
    technology:"Computer security becomes a discipline with a founding disaster.",
    regulation:"The CFAA gets teeth and precedent.",
    society:"The internet's interdependence — one student, ten percent of the net — enters public awareness." },
  causes:["ecpa","arpanet"], effects:[] },

{ id:"wwwproposal", year:1989, date:"March 1989", era:5, cat:"internet",
  title:"Berners-Lee Proposes the Web",
  wiki:"Tim Berners-Lee", gallery:["World Wide Web","CERN","Information Management: A Proposal"],
  summary:"'Vague but exciting,' his supervisor writes on the memo. Hypertext plus the internet equals the World Wide Web.",
  importance:"Tim Berners-Lee's proposal for linked information management at CERN — implemented by 1990 as HTTP, HTML, and the first browser-server pair, and opened royalty-free to the world in 1993 — created the layer that made the internet humanly usable. The decision not to patent or toll the web is among the most consequential acts of renunciation in economic history: the commons on which the next gallery's empires, and their regulators, would all be built.",
  impact:{
    communications:"The internet acquires its universal interface — documents, links, addresses for everything.",
    society:"Publishing becomes free in both senses; the read-write planet begins.",
    power:"A royalty-free standard creates trillions in value its inventor declined to own.",
    technology:"URL, HTTP, HTML: three simple standards as civilization-scale infrastructure." },
  causes:["arpanet"], effects:["webpublic","mosaic"] },

{ id:"tiananmen", year:1989, date:"June 4, 1989", era:5, cat:"general",
  title:"Tiananmen Square",
  wiki:"1989 Tiananmen Square protests and massacre", gallery:["Tank Man","Tiananmen"],
  summary:"Students and workers fill the square demanding reform; the army clears it with gunfire. China chooses markets without political opening.",
  importance:"The protests — students at the front, but workers' federations crucially among them — ended in massacre and mass arrest. The party's verdict held: economic liberalization would proceed, political monopoly would not yield, and the information apparatus would ensure the event's domestic erasure. The Great Firewall's later censorship regime and the world's most comprehensive surveillance state grew from this settlement. 'Tank Man' became globally iconic — and domestically unsearchable.",
  impact:{
    government:"Authoritarian resilience demonstrated: market economy fused to political monopoly.",
    surveillance:"Censorship and monitoring become core technologies of Chinese governance — eventually exported.",
    labor:"Independent worker organization remains the party's deepest red line — the official union its only legal form.",
    society:"The memory war — erasure at home, icon abroad — previews the censored internet's geopolitics." },
  causes:["dengreform","may68"], effects:["greatfirewall"] },

{ id:"berlinwall", year:1989, date:"November 9, 1989", era:5, cat:"general",
  title:"The Berlin Wall Falls",
  wiki:"Fall of the Berlin Wall", gallery:["Berlin Wall","Revolutions of 1989","Stasi"],
  summary:"East Germany's border opens amid the revolutions of 1989; within two years the Soviet Union itself dissolves.",
  importance:"Solidarity's Polish elections, Hungary's opened border, and mass demonstrations brought the bloc down in months — peacefully nearly everywhere. The Stasi's files, opened to their subjects, gave the world its most complete anatomy of a surveillance state: one informer per sixty-three citizens. The Cold War's end redirected intelligence apparatuses, globalized capitalism into the former bloc with wrenching labor shocks, and closed the seventy-four-year arc opened in Petrograd in 1917.",
  impact:{
    government:"The bipolar world ends; liberal capitalism enjoys its brief unipolar 'end of history.'",
    surveillance:"The Stasi archive becomes the reference case of total surveillance — and of confronting it through file access.",
    labor:"Shock therapy devastates Eastern labor markets; Russian life expectancy falls — transition's human price.",
    society:"1989 joins 1789 and 1917 in the calendar of world-remaking years." },
  causes:["solidarity","russianrev","coldwar"], effects:["webpublic"] }
);
